using System.Linq;

class CosmosQuery
{
    // EF Core 9 Cosmos provider no longer supports synchronous I/O.
    // All queries and SaveChanges calls must use async equivalents.
    async Task FindProducts(ProductContext ctx)
    {
        // Direct Cosmos SQL — still works because we preserved the
        // "Discriminator" property name via HasDiscriminator in OnModelCreating.
        var sql = "SELECT * FROM c WHERE c.Discriminator = 'Product' AND c.Sku = @sku";

        // ToList() throws in EF Core 9 Cosmos — use ToListAsync().
        var products = await ctx.Products.Where(p => p.Sku == "ABC").ToListAsync();
    }
}

